import json
import re

# Read the swift files query result
with open(var_functions.query_db:8, 'r') as f:
    swift_files = json.load(f)

# Read the languages query result
with open(var_functions.query_db:5, 'r') as f:
    swift_repos = json.load(f)

# Create a set of Swift repos for fast lookup
swift_repo_names = {repo['repo_name'] for repo in swift_repos}

# Filter swift files data to keep only files from Swift repos
swift_files_filtered = [f for f in swift_files if f['sample_repo_name'] in swift_repo_names]

# Function to extract copy count from repo_data_description
def extract_copy_count(description):
    if 'duplicated' in description.lower():
        match = re.search(r'duplicated\s+(\d+)\s+times?', description.lower())
        if match:
            return int(match.group(1))
    elif 'copied' in description.lower():
        match = re.search(r'copied\s+(\d+)\s+times?', description.lower())
        if match:
            return int(match.group(1))
    elif 'appearing' in description.lower():
        match = re.search(r'appearing\s+(\d+)\s+times?', description.lower())
        if match:
            return int(match.group(1))
    elif 'file' in description and 'times' in description:
        match = re.search(r'(\d+)\s+times', description)
        if match:
            return int(match.group(1))
    return 0

# Process all swift files
swift_data = []
for f in swift_files:
    file_id = f['id']
    repo_name = f['sample_repo_name']
    path = f['sample_path']
    description = f['repo_data_description']

    copy_count = extract_copy_count(description)
    is_binary = 'binary' in description and 'non-binary' not in description

    swift_data.append({
        'id': file_id,
        'repo_name': repo_name,
        'path': path,
        'copy_count': copy_count,
        'is_binary': is_binary,
        'description': description
    })

# Filter for non-binary files
non_binary_swift = [f for f in swift_data if not f['is_binary']]

# Group by file ID and find the most frequent
from collections import defaultdict
file_copy_counts = defaultdict(int)

for f in non_binary_swift:
    file_copy_counts[f['id']] = f['copy_count']

# Find the file ID with highest copy count
if file_copy_counts:
    max_file_id = max(file_copy_counts.items(), key=lambda x: x[1])
    most_copied_file_id = max_file_id[0]
    max_copies = max_file_id[1]

    # Get all details for this file (unique by ID as per requirement)
    most_copied_files = [f for f in non_binary_swift if f['id'] == most_copied_file_id]

    if most_copied_files:
        result_file = most_copied_files[0]  # Since ID is unique, all should be same file
        repo_of_interest = result_file['repo_name']
    else:
        repo_of_interest = None
else:
    repo_of_interest = None
    max_copies = 0

print('__RESULT__:')
print(json.dumps({
    'repo_of_interest': repo_of_interest,
    'most_copied_file_id': most_copied_file_id if file_copy_counts else None,
    'max_copies': max_copies,
    'total_non_binary_swift_files': len(non_binary_swift),
    'total_repos_considered': len(swift_repo_names)
}, indent=2))

